module xor_8bit_en (
    OUT,
    A,
    B,
    EN
);

    output reg [8-1:1-1] OUT;
    input [7:0] A;
    input [7:0] B;
    input EN;

    always @(*) begin
        if (EN) begin
            OUT = A ^ B;
        end
        else begin
            OUT = 8'b0;
        end
    end

endmodule
